script:
// ============================================
// SCRIPT CALCUL AUTO — Bon de Commande ISQ
// ISquare — Version finale avec Remise
// ============================================

// Déclencheurs sur le tableau Articles
frappe.ui.form.on('BC ISQ Item', {
    qte: function(frm, cdt, cdn) {
        calc_ligne(frm, cdt, cdn);
    },
    prix_unitaire_ht: function(frm, cdt, cdn) {
        calc_ligne(frm, cdt, cdn);
    }
});

// Déclencheur quand la Remise change
frappe.ui.form.on('Bon de Commande ISQ', {
    remise: function(frm) {
        calc_totaux(frm);
    }
});

// Calcul Total par ligne : QTE × Prix HT
function calc_ligne(frm, cdt, cdn) {
    var row = locals[cdt][cdn];
    var total = (row.qte || 0) * (row.prix_unitaire_ht || 0);
    frappe.model.set_value(cdt, cdn, 'total', total);
    calc_totaux(frm);
}

// Calcul global : HT brut → Remise → HT net → TVA 20% → TTC
function calc_totaux(frm) {

    // 1. Total HT brut (somme de toutes les lignes)
    var total_ht_brut = 0;
    (frm.doc.articles || []).forEach(function(item) {
        total_ht_brut += (item.total || 0);
    });

    // 2. Remise (0% si non saisie)
    var remise = frm.doc.remise || 0;
    var montant_remise = total_ht_brut * (remise / 100);

    // 3. Total HT net après remise
    var total_ht = total_ht_brut - montant_remise;

    // 4. TVA 20%
    var tva = total_ht * 0.20;

    // 5. Total TTC
    var total_ttc = total_ht + tva;

    // 6. Mettre à jour les champs
    frm.set_value('montant_remise', montant_remise);
    frm.set_value('total_ht', total_ht);
    frm.set_value('tva', tva);
    frm.set_value('total_ttc', total_ttc);
    frm.refresh_fields([
        'montant_remise',
        'total_ht',
        'tva',
        'total_ttc'
    ]);
}

frappe.ui.form.on('Bon de Commande ISQ', {
    référence_da: function(frm) {
        if (frm.doc.référence_da) {
            // Remplir NUMERO DE BC avec l'ID de la DA
            frm.set_value('numero_bc', frm.doc.référence_da);

            // Auto-remplir les autres champs depuis la DA
            frappe.db.get_doc('Demande Achat ISQ', frm.doc.référence_da)
            .then(da => {
                frm.set_value('demande_par', da.demande_par);
                frm.set_value('service_chantier', da.service_chantier);
                frm.set_value('date_besoin', da.date_besoin);

                // Copier les articles de la DA vers le BC
                frm.clear_table('articles');
                da.articles.forEach(item => {
                    let row = frm.add_child('articles');
                    row.numero_article = item.numero_article;
                    row.description = item.description;
                    row.unite = item.unite;
                    row.qte = item.quantite;
                });
                frm.refresh_field('articles');
                frappe.msgprint('✓ Champs remplis automatiquement depuis DA : ' + frm.doc.référence_da);
            });
        }
    }
});

frappe.ui.form.on("Fournisseur Article ISQ", {
    "désignation": function(frm, cdt, cdn) {
        const unites = {
            "Fer à béton":              "Tonne",
            "Ciment":                   "Sac",
            "Sable":                    "m³",
            "Gravier G1":               "m³",
            "Roché":                    "m³",
            "Béton prêt à l'emploi":   "m³",
            "Agglo / Parpaing":        "Unité",
            "PH / Plancher":           "Unité",
            "Brique":                  "Millier",
            "Coffrage métallique":     "m²",
            "Bois coffrage":           "m²",
            "Marbre":                  "m²",
            "Carrelage":               "m²",
            "Enduit / Plâtre":         "Sac",
            "Peinture":                "L",
            "Étanchéité":              "m²",
            "Sika / Produits chimiques":"Sac",
            "Plomberie":               "Unité",
            "Électricité":             "Unité",
            "Menuiserie aluminium":    "m²",
            "Menuiserie métallique":   "m²",
            "Climatisation":           "Unité",
            "Engin / Location":        "Heure",
            "Transport":               "Forfait",
            "Matériel OCA":            "Unité",
            "Bureau chantier":         "Unité",
            "Réparation matériel":     "Forfait",
            "Divers":                  "Unité",
        };
        let row = locals[cdt][cdn];
        let unite = unites[row.désignation];
        if (unite) {
            frappe.model.set_value(cdt, cdn, "unité", unite);
        }
    }
});

frappe.ui.form.on('Demande de Devis ISQ', {
    refresh(frm) {
        // Applique le surlignage au chargement du document
        surligner_moins_cher(frm);
    }
});

// Événements liés à votre tableau enfant 'DD ISQ Synthese'
frappe.ui.form.on('DD ISQ Synthese', {
    // 1. Déclenchement automatique dès que le fournisseur change sur une ligne
    fournisseur(frm, cdt, cdn) {
        recuperer_infos_catalogue(frm, cdt, cdn);
    },

    // 2. Déclenchement automatique dès que l'article change sur une ligne
    article(frm, cdt, cdn) {
        recuperer_infos_catalogue(frm, cdt, cdn);
    },

    // Recalcul en direct si l'acheteur modifie manuellement le prix ou la quantité
    prix_unitaire(frm, cdt, cdn) {
        const row = locals[cdt][cdn];
        frappe.model.set_value(cdt, cdn, 'total_ht', (row.qty || row.quantite || 0) * (row.prix_unitaire || 0));
        surligner_moins_cher(frm);
    },

    quantite(frm, cdt, cdn) {
        const row = locals[cdt][cdn];
        frappe.model.set_value(cdt, cdn, 'total_ht', (row.qty || row.quantite || 0) * (row.prix_unitaire || 0));
        surligner_moins_cher(frm);
    },

    // Règle d'exclusivité : un seul fournisseur retenu par article
    retenu(frm, cdt, cdn) {
        const row = locals[cdt][cdn];
        if (row.retenu) {
            (frm.doc.synthese_devis || []).forEach(r => {
                if (r.name !== cdn && r.article === row.article) {
                    frappe.model.set_value(r.doctype, r.name, 'retenu', 0);
                }
            });
            frm.refresh_field('synthese_devis');
        }
    }
});

// Fonction qui va chercher les informations de manière dynamique sans recharger la page
function recuperer_infos_catalogue(frm, cdt, cdn) {
    const row = locals[cdt][cdn];

    // On n'exécute que si le fournisseur ET l'article sont saisis sur la ligne
    if (row.fournisseur && row.article) {

        // Aller chercher la quantité demandée initialement dans le tableau du haut pour cet article
        let qte_initiale = 0;
        if (frm.doc.articles) {
            let art_doc = frm.doc.articles.find(a => a.item === row.article || a.article === row.article);
            if (art_doc) {
                qte_initiale = art_doc.qty || art_doc.quantite || 0;
            }
        }

        // Appel rapide à la base de données pour récupérer le prix dans la fiche du fournisseur concerné
        frappe.db.get_value('Fournisseur ISQ', row.fournisseur, ['transport'], (r) => {

            // On initialise le numéro et la date par défaut pour éviter le blocage des champs obligatoires (image_a5d04a.png)
            frappe.model.set_value(cdt, cdn, 'no_devis', "En attente");
            frappe.model.set_value(cdt, cdn, 'date_devis', frappe.datetime.get_today());
            frappe.model.set_value(cdt, cdn, 'quantite', qte_initiale);

            // On cherche le prix de l'article dans la Child Table de la fiche Fournisseur
            frappe.call({
                method: 'frappe.client.get',
                args: {
                    doctype: 'Fournisseur ISQ',
                    name: row.fournisseur
                },
                callback: function(res) {
                    let prix_trouve = 0;
                    if (res.message && res.message.table_articles) {
                        let article_catalogue = res.message.table_articles.find(a => a.article === row.article);
                        if (article_catalogue) {
                            prix_trouve = article_catalogue.prix_unitaire || 0;
                        }
                    }

                    // Injection automatique du prix et calcul instantané du total
                    frappe.model.set_value(cdt, cdn, 'prix_unitaire', prix_trouve);
                    frappe.model.set_value(cdt, cdn, 'total_ht', qte_initiale * prix_trouve);

                    // Rafraîchir l'affichage et lancer le surlignage rouge
                    frm.refresh_field('synthese_devis');
                    surligner_moins_cher(frm);
                }
            });
        });
    }
}

// Fonction de surlignage en Rouge du prix le plus bas
function surligner_moins_cher(frm) {
    const rows = frm.doc.synthese_devis || [];
    const minParArticle = {};

    // Étape 1 : Trouver le prix minimum pour chaque article unique
    rows.forEach(r => {
        if (r.prix_unitaire == null || r.prix_unitaire === 0) return;
        if (!(r.article in minParArticle) || r.prix_unitaire < minParArticle[r.article]) {
            minParArticle[r.article] = r.prix_unitaire;
        }
    });

    // Étape 2 : Appliquer la couleur rouge doux (#FCE8E6) sur les lignes gagnantes
    const grid = frm.fields_dict.synthese_devis.grid;
    rows.forEach(r => {
        const gr = grid.grid_rows_by_docname[r.name];
        if (!gr || !gr.row) return;

        const estMin = (r.prix_unitaire != null && r.prix_unitaire === minParArticle[r.article]);
        // #FCE8E6 est un rouge/rose pastel très lisible pour les yeux en entreprise
        gr.row.css('background-color', estMin ? '#FCE8E6' : ''); 
    });
}

frappe.ui.form.on('Bon de Commande ISQ', {
    refresh: function(frm) {
        if (!frm.is_new()) {
            frm.add_custom_button('Imprimer', () => frm.print_doc());
        }
    }
});
